import requests
from requests.sessions import SessionRedirectMixin

class SafeSession(SessionRedirectMixin):
    def __init__(self):
        self.max_redirects = 30
        self.cookies = {}
        self.trust_env = False

    def should_strip_auth(self, old_url, new_url):
        old_parsed = requests.compat.urlparse(old_url)
        new_parsed = requests.compat.urlparse(new_url)
        if old_parsed.hostname != new_parsed.hostname:
            return True
        if (old_parsed.scheme == 'http' and old_parsed.port in (80, None)
                and new_parsed.scheme == 'https' and new_parsed.port in (443, None)):
            return False
        return old_parsed.port != new_parsed.port or old_parsed.scheme != new_parsed.scheme

    def rebuild_auth(self, prepared_request, response):
        headers = prepared_request.headers
        url = prepared_request.url

        if 'Authorization' in headers and self.should_strip_auth(response.request.url, url):
            del headers['Authorization']

        new_auth = requests.utils.get_netrc_auth(url) if self.trust_env else None
        if new_auth is not None:
            prepared_request.prepare_auth(new_auth)

s = SafeSession()
prepared = requests.PreparedRequest()
prepared.headers = {'Authorization': 'Basic abc123'}
prepared.url = 'http://example.com'
response = requests.Response()
